module TopModule;
    reg [3:0] input_values;
    wire output_value;

    xnor4 uut (.a(input_values), .y(output_value));

    initial begin
        $readmemb("input.txt", input_values);
        #10 $finish;
    end

    initial begin
        $monitor("At time %t, input = %b, output = %b", $time, input_values, output_value);
    end
endmodule

